```python
import math

def smallest_Divisor(n):
    # Wenn n eine Primzahl ist, dann ist sie ihr eigener kleinsten Primteiler
    if n == 2:
        return n

    # Alle ungeraden Zahlen größer als 2 sind keine Primzahlen
    if n % 2 == 0:
        return 2

    # Überprüfe alle ungeraden Zahlen von 3 bis zur Quadratwurzel von n
    for i in range(3, int(math.sqrt(n)) + 1, 2):
        # Wenn n durch i teilbar ist, dann ist i ein Teiler
        if n % i == 0:
            # Überprüfe, ob i eine Primzahl ist
            if is_prime(i):
                return i

    # Wenn keine Primzahlen gefunden wurden, dann ist n selbst eine Primzahl
    return n

def is_prime(n):
    # 0 und 1 sind keine Primzahlen
    if n < 2:
        return False

    # Alle geraden Zahlen größer als 2 sind keine Primzahlen
    if n % 2 == 0:
        return False

    # Überprüfe alle ungeraden Zahlen von 3 bis zur Quadratwurzel von n
    for i in range(3, int(math.sqrt(n)) + 1, 2):
        # Wenn n durch i teilbar ist, dann ist n keine Primzahl
        if n % i == 0:
            return False

    # Wenn keine Teiler gefunden wurden, dann ist n eine Primzahl
    return True
```

