```python
def add_dict(dict1, dict2):
    # Überprüfen, ob beide Eingabeparameter Wörterbücher sind
    if not isinstance(dict1, dict) or not isinstance(dict2, dict):
        raise ValueError("Beide Eingabeparameter müssen Wörterbücher sein")

    # Ein neues Wörterbuch erstellen, das die Werte der beiden Eingabewörterbücher enthält
    result = {}

    # Alle Schlüssel und Werte aus dem ersten Wörterbuch in das Ergebnis-Wörterbuch übernehmen
    for key, value in dict1.items():
        result[key] = value

    # Alle Schlüssel und Werte aus dem zweiten Wörterbuch in das Ergebnis-Wörterbuch übernehmen
    for key, value in dict2.items():
        # Wenn der Schlüssel bereits im Ergebnis-Wörterbuch vorhanden ist, addieren wir die Werte
        if key in result:
            result[key] += value
        # Wenn der Schlüssel nicht im Ergebnis-Wörterbuch vorhanden ist, fügen wir ihn hinzu
        else:
            result[key] = value

    # Das Ergebnis-Wörterbuch zurückgeben
    return result
```

Beispiel:

```python
dict1 = {'a': 1, 'b': 2, 'c': 3}
dict2 = {'b': 4, 'c': 5, 'd': 6}

result = add_dict(dict1, dict2)
print(result)  # {'a': 1, 'b': 6, 'c': 8, 'd': 6}
```

